function unidades(n){return['cero','uno','dos','tres','cuatro','cinco','seis','siete','ocho','nueve'][n]}function decenas(n){const e={10:'diez',11:'once',12:'doce',13:'trece',14:'catorce',15:'quince',16:'dieciséis',17:'diecisiete',18:'dieciocho',19:'diecinueve'},d=['','','veinte','treinta','cuarenta','cincuenta','sesenta','setenta','ochenta','noventa'];if(n<10)return unidades(n);if(n<20)return e[n];const t=Math.floor(n/10),u=n%10;return d[t]+(u>0?' y '+unidades(u):'')}function centenas(n){const c=['cien','ciento','doscientos','trescientos','cuatrocientos','quinientos','seiscientos','setecientos','ochocientos','novecientos'];if(n<100)return decenas(n);if(n===100)return c[0];const h=Math.floor(n/100),r=n%100;return c[h]+(r>0?' '+decenas(r):'')}function miles(n){if(n<1000)return centenas(n);const m=Math.floor(n/1000),r=n%1000,l=m===1?'mil':convertirEntero(m)+' mil';return l+(r>0?' '+centenas(r):'')}function convertirEntero(n){if(n<1000)return centenas(n);if(n<1e6)return miles(n);return'Número muy grande'}function stevstring(x){const p=x.toFixed(2).split('.'),e=parseInt(p[0]),d=parseInt(p[1]),t=convertirEntero(e),s=d>0?' con '+decenas(d)+' centavos':'';return t+' soles'+s}
